// Parse + validate Google Ads Campaign performance export -> fact rows.
let text = String($input.first().json.data || '');
text = text.replace(/^\uFEFF/, '');
if (text.indexOf('\u0000') >= 0) {
  throw new Error('Google Ads CSV rejected - file appears UTF-16 encoded; re-export as plain CSV (UTF-8), not Excel CSV');
}

function parseCSV(t, delim) {
  const rows = []; let row = []; let cur = ''; let inQ = false;
  for (let i = 0; i < t.length; i++) {
    const ch = t[i];
    if (inQ) {
      if (ch === '"') { if (t[i + 1] === '"') { cur += '"'; i++; } else { inQ = false; } }
      else { cur += ch; }
    } else if (ch === '"') { inQ = true; }
    else if (ch === delim) { row.push(cur); cur = ''; }
    else if (ch === '\n') { row.push(cur); rows.push(row); row = []; cur = ''; }
    else if (ch === '\r') { /* skip */ }
    else { cur += ch; }
  }
  if (cur.length || row.length) { row.push(cur); rows.push(row); }
  return rows;
}

const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/ +/g, ' ').trim();

// Google Ads exports put a title + date-range preamble above the header. Find the header line.
const lines = text.split('\n');
let delim = ',';
for (let i = 0; i < Math.min(lines.length, 10); i++) {
  if (lines[i].indexOf('\t') >= 0) { delim = '\t'; break; }
}
const all = parseCSV(text, delim).filter((r) => r.some((c) => String(c).trim() !== ''));
let hIdx = -1;
for (let i = 0; i < Math.min(all.length, 10); i++) {
  const h = all[i].map(norm);
  const hasCampaign = h.some((c) => c === 'campaign' || c.indexOf('campaign') >= 0);
  const hasMetric = h.some((c) => c.indexOf('cost') >= 0 || c.indexOf('impr') >= 0);
  if (hasCampaign && hasMetric) { hIdx = i; break; }
}
if (hIdx < 0) {
  throw new Error('Google Ads CSV rejected - header row not found (expected Campaign + Cost/Impressions columns). Use the Campaign performance report with daily breakdown.');
}
const headers = all[hIdx].map(norm);
function col() {
  for (let n = 0; n < arguments.length; n++) {
    const want = arguments[n];
    let i = headers.findIndex((h) => h === want);
    if (i < 0) i = headers.findIndex((h) => h.indexOf(want) >= 0);
    if (i >= 0) return i;
  }
  return -1;
}
const iDate = col('day', 'date');
const iId = col('campaign id');
let iName = headers.findIndex((h) => h === 'campaign');
if (iName < 0) iName = col('campaign');
if (iName === iId) iName = headers.findIndex((h, idx) => h.indexOf('campaign') >= 0 && idx !== iId);
const iSpend = col('cost', 'total cost', 'spend');
const iImpr = col('impr', 'impressions');
const iClicks = col('clicks');
const iConv = col('conversions', 'conv');
const missing = [];
if (iDate < 0) missing.push('Day/Date');
if (iName < 0) missing.push('Campaign');
if (iSpend < 0) missing.push('Cost');
if (iImpr < 0) missing.push('Impressions');
if (iClicks < 0) missing.push('Clicks');
if (missing.length) {
  throw new Error('Google Ads CSV rejected - missing required columns: ' + missing.join(', '));
}

function num(v) {
  const s = String(v == null ? '' : v).trim();
  if (s === '--' || s === '') return 0;
  const n = Number(s.replace(/[^0-9.\-]/g, ''));
  return isNaN(n) ? 0 : n;
}
function toISO(v) {
  const s = String(v || '').trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const t = Date.parse(s);
  if (!isNaN(t)) return new Date(t).toISOString().slice(0, 10);
  return null;
}
function slug(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 60);
}
function regionFromName(name) {
  const n = ' ' + String(name || '').toLowerCase() + ' ';
  if (/(belux|benelux|belgium|luxembourg)/.test(n)) return 'BeLux';
  if (/(netherlands|holland)/.test(n) || / nl /.test(n) || /[ _\-]nl[ _\-]/.test(n)) return 'NL';
  if (/(uki|uk i|uk and ireland|united kingdom|ireland)/.test(n) || / uk /.test(n) || /[ _\-]uk[ _\-]/.test(n)) return 'UKI';
  return 'UNASSIGNED';
}

const agg = {};
let rowsIn = 0;
let issues = 0;
for (let i = hIdx + 1; i < all.length; i++) {
  const r = all[i];
  const nameRaw = String(r[iName] || '').trim();
  const nameNorm = norm(nameRaw);
  if (!nameRaw) continue;
  if (nameNorm.indexOf('total') === 0) continue; // 'Total: ...' footer rows
  rowsIn++;
  const date = toISO(r[iDate]);
  if (!date) { issues++; continue; }
  const idRaw = iId >= 0 ? String(r[iId] || '').trim() : '';
  const ck = idRaw ? 'GADS_' + idRaw : 'GADS_' + slug(nameRaw);
  const region = regionFromName(nameRaw);
  const key = ck + '|' + region + '|' + date;
  if (!agg[key]) {
    agg[key] = { campaign_key: ck, campaign_name: nameRaw, region_code: region,
      channel_name: 'Paid Search', activity_date: date, source: 'google_ads',
      spend: 0, impressions: 0, clicks: 0, leads: 0 };
  }
  const a = agg[key];
  a.spend += num(r[iSpend]);
  a.impressions += num(r[iImpr]);
  a.clicks += num(r[iClicks]);
  a.leads += iConv >= 0 ? num(r[iConv]) : 0; // TODO: confirm conversions==leads with Margot
}

const out = Object.values(agg);
if (out.length === 0) {
  throw new Error('Google Ads CSV rejected - no valid data rows after validation (rows in: ' + rowsIn + ', invalid: ' + issues + ')');
}
const meta = { rows_in: rowsIn, issues: issues, issue_pct: rowsIn ? Number(((issues / rowsIn) * 100).toFixed(2)) : 0 };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));

// Distinct campaigns for dim_campaign upsert.
const seen = {};
const out = [];
for (const item of $('Parse + Validate Ads CSV').all()) {
  const j = item.json;
  if (seen[j.campaign_key]) continue;
  seen[j.campaign_key] = 1;
  out.push({ json: { campaign_key: j.campaign_key, campaign_name: j.campaign_name,
    channel_name: j.channel_name, source_system: 'google_ads' } });
}
return out;
